mapper.select:
, CASE WHEN #{currentUserId, jdbcType=BIGINT} IS NOT NULL THEN EXISTS(SELECT 1 FROM reading_group_members m WHERE m.group_id = rg.id AND m.user_id = #{currentUserId, jdbcType=BIGINT} AND m.is_active = TRUE) ELSE FALSE END AS is_member, NULL AS my_role, FALSE AS has_pending_request FROM reading_groups rg JOIN users uo ON uo.id = rg.owner_id WHERE rg.is_active = TRUE AND rg.group_type IN ('public', 'invite_only')
AND (rg.name ILIKE '%' || #{search} || '%' OR rg.description ILIKE '%' || #{search} || '%')
AND rg.focus_type = #{focusType}
ORDER BY rg.member_count DESC, rg.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM reading_groups WHERE is_active = TRUE AND group_type IN ('public','invite_only')
AND (name ILIKE '%' || #{search} || '%' OR description ILIKE '%' || #{search} || '%')
AND focus_type = #{focusType}

SELECT COUNT(*) FROM group_discussions
WHERE group_id = #{groupId} AND parent_id IS NULL AND is_deleted = FALSE
AND schedule_id = #{scheduleId}

mapper.update:
UPDATE group_join_requests SET
status = #{status}, reviewed_by = #{reviewedBy}, reviewed_at = NOW()
WHERE id = #{id}
